KillMonsterWeekRank = class("KillMonsterWeekRank", BaseRank)

function KillMonsterWeekRank:init()
    self.rankKey = Define.RankKey.KillMonsterWeek .. RankConfig.RankWeekKey
    self.pageSize = 7
    self.rowNum = 4
    ---每一列 偏移位置 和 列头
    self.rowKey = { BaseRank.LangKey.Rank, BaseRank.LangKey.Name, BaseRank.LangKey.KillAmount, BaseRank.LangKey.Level }
    self.titleOffset = { -2.5, 1.75 }
    self.countDownOffset = { -2.5, 1.5 }
    self.countDownTimeOffset = { 2.4, 1.48 }
    self.rowKeyOffsetX = { -2.5, -0.65, 1.2, 2.5 }
    self.rowKeyOffsetY = { 1.08, 0.65, 0.215, -0.22, -0.655, -1.09, -1.525, -1.96 }
end

function KillMonsterWeekRank:updateKey()
    self.rankKey = Define.RankKey.KillMonsterWeek .. RankConfig.RankWeekKey
    MaxRecordHelper:getRecord(self.rankKey, self.curPage, self.pageSize, function(list)
        self.curList = list
        self:printData(self.curList)
    end)
end

function KillMonsterWeekRank:printData(list, scale, alpha)
    scale = scale or 1
    alpha = alpha or 1
    local globalRender = Blockman.Instance().m_globalRender
    if not globalRender then
        return
    end
    for index, record in pairs(list) do
        local rowKeyOffsetY = self.rowKeyOffsetY[index + 1]

        globalRender:luaAddWallText(5, -1, record.rank,
                self:getNewPosition(self.config.effectPos, self.config.scale, self.config.yaw, self.rowKeyOffsetX[1], rowKeyOffsetY),
                self.config.scale * scale, self.config.yaw, 0, { 1, 1, 1, 1 * alpha })

        local values = StringUtil.split(record.value, ",")
        globalRender:luaAddWallText(5, -1, values[1],
                self:getNewPosition(self.config.effectPos, self.config.scale, self.config.yaw, self.rowKeyOffsetX[2], rowKeyOffsetY),
                self.config.scale * scale, self.config.yaw, 0, { 1, 1, 1, 1 * alpha })

        globalRender:luaAddWallText(5, -1, math.floor(record.score / 1000),
                self:getNewPosition(self.config.effectPos, self.config.scale, self.config.yaw, self.rowKeyOffsetX[3], rowKeyOffsetY),
                self.config.scale * scale, self.config.yaw, 0, { 1, 1, 1, 1 * alpha })

        globalRender:luaAddWallText(5, -1, math.fmod(record.score, 1000),
                self:getNewPosition(self.config.effectPos, self.config.scale, self.config.yaw, self.rowKeyOffsetX[4], rowKeyOffsetY),
                self.config.scale * scale, self.config.yaw, 0, { 1, 1, 1, 1 * alpha })

    end
end

function KillMonsterWeekRank:refreshActor(number)
    MaxRecordHelper:getRecord(self.rankKey, 1, number, function(list)
        local userIds = {}
        for _, record in pairs(list) do
            local values = StringUtil.split(record.value, ",")
            table.insert(userIds, tonumber(values[1]))
        end
        self:changeActor(userIds)
    end)
end